import{_ as r,o as d,c as o,a2 as n}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"AI · 关键术语表","description":"","frontmatter":{},"headers":[],"relativePath":"AI/关键术语表.md","filePath":"AI/关键术语表.md","lastUpdated":1781535932000}'),e={name:"AI/关键术语表.md"};function s(a,t,g,i,h,l){return d(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="ai-·-关键术语表" tabindex="-1">AI · 关键术语表 <a class="header-anchor" href="#ai-·-关键术语表" aria-label="Permalink to &quot;AI · 关键术语表&quot;">​</a></h1><p><strong>用途：</strong> PE/VC 一级市场投资研究参考</p><hr><h2 id="一、基础概念" tabindex="-1">一、基础概念 <a class="header-anchor" href="#一、基础概念" aria-label="Permalink to &quot;一、基础概念&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>说明</th></tr></thead><tbody><tr><td><strong>大模型 / LLM</strong></td><td>Large Language Model，大规模语言模型，如 GPT-4、GLM-4</td></tr><tr><td><strong>多模态</strong></td><td>Multimodal，同时处理文本+图像+音频+视频的模型能力</td></tr><tr><td><strong>AGI</strong></td><td>Artificial General Intelligence，通用人工智能</td></tr><tr><td><strong>AI Agent</strong></td><td>能自主感知、规划、执行任务的 AI 系统</td></tr><tr><td><strong>RAG</strong></td><td>Retrieval-Augmented Generation，检索增强生成，外挂知识库</td></tr><tr><td><strong>MoE</strong></td><td>Mixture of Experts，混合专家模型，提高参数效率</td></tr><tr><td><strong>Transformer</strong></td><td>基础模型架构，Attention is All You Need</td></tr><tr><td><strong>Diffusion</strong></td><td>扩散模型，图像/视频生成核心架构（Stable Diffusion/Sora）</td></tr><tr><td><strong>RLHF</strong></td><td>Reinforcement Learning from Human Feedback，人类反馈强化学习</td></tr><tr><td><strong>SFT</strong></td><td>Supervised Fine-Tuning，监督微调</td></tr><tr><td><strong>Prompt Engineering</strong></td><td>提示词工程，优化输入以获得更好的模型输出</td></tr><tr><td><strong>温度 (Temperature)</strong></td><td>控制生成随机性的参数，越低越确定</td></tr><tr><td><strong>幻觉 (Hallucination)</strong></td><td>模型生成看似合理但实际错误的内容</td></tr></tbody></table><h2 id="二、模型训练-优化" tabindex="-1">二、模型训练/优化 <a class="header-anchor" href="#二、模型训练-优化" aria-label="Permalink to &quot;二、模型训练/优化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>说明</th></tr></thead><tbody><tr><td><strong>预训练</strong></td><td>Pre-training，在海量数据上训练基础模型</td></tr><tr><td><strong>微调</strong></td><td>Fine-tuning，在特定领域数据上调整模型</td></tr><tr><td><strong>LoRA</strong></td><td>Low-Rank Adaptation，高效微调方法，修改少量参数</td></tr><tr><td><strong>量化</strong></td><td>Quantization，降低模型精度（FP16→INT8/INT4）以减小体积</td></tr><tr><td><strong>蒸馏</strong></td><td>Knowledge Distillation，大模型教小模型</td></tr><tr><td><strong>剪枝</strong></td><td>Pruning，删除不重要的模型参数</td></tr><tr><td><strong>上下文窗口</strong></td><td>Context Window，模型能处理的输入长度（Token数）</td></tr><tr><td><strong>注意力机制</strong></td><td>Attention，Transformer 核心，让模型关注输入的不同部分</td></tr><tr><td><strong>Scaling Law</strong></td><td>模型性能随参数量/数据量/算力增长的可预测规律</td></tr></tbody></table><h2 id="三、基础设施" tabindex="-1">三、基础设施 <a class="header-anchor" href="#三、基础设施" aria-label="Permalink to &quot;三、基础设施&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>说明</th></tr></thead><tbody><tr><td><strong>GPU</strong></td><td>Graphics Processing Unit，AI 训练/推理主力芯片</td></tr><tr><td><strong>TPU</strong></td><td>Tensor Processing Unit，Google 专为 TensorFlow 设计</td></tr><tr><td><strong>NPU</strong></td><td>Neural Processing Unit，神经网络加速器</td></tr><tr><td><strong>HBM</strong></td><td>High Bandwidth Memory，高带宽显存（HBM2e/HBM3/HBM4）</td></tr><tr><td><strong>CoWoS</strong></td><td>Chip-on-Wafer-on-Substrate，台积电 2.5D 先进封装</td></tr><tr><td><strong>CXL</strong></td><td>Compute Express Link，高速缓存一致性互联协议</td></tr><tr><td><strong>存算一体</strong></td><td>Processing-in-Memory (PIM)，在存储中计算，减少数据搬运</td></tr><tr><td><strong>算力租赁</strong></td><td>按需租用 GPU/算力，如 CoreWeave/Vast.ai</td></tr><tr><td><strong>FLOPS</strong></td><td>FLoating-point Operations Per Second，算力单位</td></tr><tr><td><strong>TOPS</strong></td><td>Trillion Operations Per Second，常用于端侧AI芯片</td></tr><tr><td><strong>TDP</strong></td><td>Thermal Design Power，功耗散热设计</td></tr><tr><td><strong>智算中心</strong></td><td>AI 专用数据中心，部署大量 GPU/NPU</td></tr></tbody></table><h2 id="四、生成式-ai" tabindex="-1">四、生成式 AI <a class="header-anchor" href="#四、生成式-ai" aria-label="Permalink to &quot;四、生成式 AI&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>说明</th></tr></thead><tbody><tr><td><strong>AIGC</strong></td><td>AI Generated Content，AI 生成内容</td></tr><tr><td><strong>文生图</strong></td><td>Text-to-Image，如 Midjourney/DALL-E/Stable Diffusion</td></tr><tr><td><strong>文生视频</strong></td><td>Text-to-Video，如 Sora/可灵/Emu Video</td></tr><tr><td><strong>文生音乐</strong></td><td>Text-to-Music，如 Suno/Udio</td></tr><tr><td><strong>数字人</strong></td><td>Digital Human，AI 驱动的虚拟人形象</td></tr><tr><td><strong>文生3D</strong></td><td>Text-to-3D，如 Meshy/Luma Genie</td></tr><tr><td><strong>ControlNet</strong></td><td>精确控制图像生成姿势/构图的技术</td></tr><tr><td><strong>Lora（不是LoRA）</strong></td><td>分布式个性化微调模型文件</td></tr></tbody></table><h2 id="五、ai-应用-行业" tabindex="-1">五、AI 应用/行业 <a class="header-anchor" href="#五、ai-应用-行业" aria-label="Permalink to &quot;五、AI 应用/行业&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>说明</th></tr></thead><tbody><tr><td><strong>Copilot</strong></td><td>AI 编程/办公助手模式</td></tr><tr><td><strong>RPA + AI</strong></td><td>AI 增强的机器人流程自动化</td></tr><tr><td><strong>AI 辅助诊断</strong></td><td>AI 辅助医学影像/病理/心电图诊断</td></tr><tr><td><strong>智能投研</strong></td><td>AI 辅助投资研究/数据分析</td></tr><tr><td><strong>合成数据</strong></td><td>AI 生成的训练数据（解决真实数据不足）</td></tr><tr><td><strong>边缘 AI</strong></td><td>终端设备上运行的 AI，无需云端</td></tr><tr><td><strong>MLOps</strong></td><td>Machine Learning Operations，模型部署运维流水线</td></tr><tr><td><strong>AI 安全</strong></td><td>AI 对齐/红队测试/对抗攻击防御</td></tr><tr><td><strong>可解释性 AI</strong></td><td>XAI，理解模型决策原因的技术</td></tr></tbody></table><h2 id="六、ai-公司-产品名-中国" tabindex="-1">六、AI 公司/产品名（中国） <a class="header-anchor" href="#六、ai-公司-产品名-中国" aria-label="Permalink to &quot;六、AI 公司/产品名（中国）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th></tr></thead><tbody><tr><td><strong>智谱 AI / GLM</strong></td><td>清华系大模型，ChatGLM系列，全栈布局</td></tr><tr><td><strong>月之暗面 / Kimi</strong></td><td>长上下文（200万字）大模型，C端产品</td></tr><tr><td><strong>百川智能 / Baichuan</strong></td><td>搜狗王小川创立，开源+闭源双路线</td></tr><tr><td><strong>零一万物 / 01.AI</strong></td><td>李开复创立，多模态+全球化</td></tr><tr><td><strong>DeepSeek</strong></td><td>幻方量化旗下，技术创新驱动（MoE架构）</td></tr><tr><td><strong>Minimax</strong></td><td>稀宇科技，语音+视频+文本多模态</td></tr><tr><td><strong>面壁智能</strong></td><td>清华系，端侧模型（MiniCPM）</td></tr><tr><td><strong>阶跃星辰</strong></td><td>微软亚洲研究院背景</td></tr><tr><td><strong>字节豆包</strong></td><td>字节跳动大模型产品</td></tr><tr><td><strong>通义千问</strong></td><td>阿里大模型系列</td></tr><tr><td><strong>文心一言</strong></td><td>百度大模型产品</td></tr></tbody></table>',15)])])}const u=r(e,[["render",s]]);export{b as __pageData,u as default};
